<template>
    <div ref="chartContainer"></div>
</template>

<script>
import * as d3 from 'd3';
export default {
    name: 'visComponent',
    data() {
        return {
            graphData: null,
            simulation: null,
            svgWidth: 1500,
            svgHeight: 3000,
            nodeRadius: 16,
        };
    },
    async mounted() {
        try {
            const response = await fetch("./assets/Top.json"); // 使用实际的JSON文件路径
            if (!response.ok) throw new Error('Network response was not ok');
            this.graphData = await response.json();
            this.renderChart();
        } catch (error) {
            console.error("Failed to fetch graph data: ", error);
        }
    },
    methods: {
        renderChart() {
            if (this.graphData) {
                console.log("data ok!")
                const margin = 120;
                const links = this.graphData.links.map(d => ({ ...d }));
                const nodes = this.graphData.nodes.map(d => ({ ...d }));
                const spacing = 120;
                const cnt=0.15;
                //计算页面高度
                // const maxCnt = Math.max(nodes.filter(node => node.group === 1).length, nodes.filter(node => node.group === 2).length)
                const maxCnt = 30;
                this.svgHeight = margin * maxCnt ;


                nodes.forEach((d) => {
                    // 把group为1的结点固定在最上面
          /*          if (d.group === 1) {
                        d.fy=margin*cnt;//固定y坐标在最上面
                        // 计算均匀分布的x坐标
                        const group1Nodes = nodes.filter(node => node.group === 1);
                        d.fx = 0.5*this.svgWidth+(group1Nodes.indexOf(d) -group1Nodes.length/2)*spacing;
                        }
                    // 把group为2的结点固定在第2行
                    if (d.group === 2) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第2行
                        // 计算均匀分布的x坐标
                        const group2Nodes = nodes.filter(node => node.group === 2);
                        d.fx = 0.5*this.svgWidth+(group2Nodes.indexOf(d) -group2Nodes.length/2)*spacing;
                    }
                    // 把group为3的结点设定在第3列
                    if (d.group === 3) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第3行
                        // 计算均匀分布的x坐标
                        const group3Nodes = nodes.filter(node => node.group === 3);
                        d.fx = 0.5*this.svgWidth+(group3Nodes.indexOf(d) -group3Nodes.length/2)*spacing*1.1;
                    }
                    // 把group为4的结点设定在第4行
                    if (d.group === 4) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第4行
                        // 计算均匀分布的x坐标
                        const group4Nodes = nodes.filter(node => node.group === 4);
                        d.fx = 0.5*this.svgWidth+(group4Nodes.indexOf(d) -group4Nodes.length/2)*spacing;
                    }
                    // 把group为5的结点设定在第5行
                    if (d.group === 5) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第5行
                        // 计算均匀分布的x坐标
                        const group5Nodes = nodes.filter(node => node.group === 5);
                        d.fx = 0.5*this.svgWidth+(group5Nodes.indexOf(d) -group5Nodes.length/2)*spacing;
                    }
                    // 把group为6的结点设定在第6行
                    if (d.group === 6) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第6行
                        // 计算均匀分布的x坐标
                        const group6Nodes = nodes.filter(node => node.group === 6);
                        d.fx = 0.5*this.svgWidth+(group6Nodes.indexOf(d) -group6Nodes.length/2)*spacing;
                    }
                    // 把group为7的结点设定在第7行
                    if (d.group === 7) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第7行
                        // 计算均匀分布的x坐标
                        const group7Nodes = nodes.filter(node => node.group === 7);
                        d.fx = 0.5*this.svgWidth+(group7Nodes.indexOf(d) -group7Nodes.length/2)*spacing;
                    }
                    // 把group为8的结点设定在第8行
                    if (d.group === 8) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第8行
                        // 计算均匀分布的x坐标
                        const group8Nodes = nodes.filter(node => node.group === 8);
                        d.fx = 0.5*this.svgWidth+(group8Nodes.indexOf(d) -group8Nodes.length/2)*spacing;
                    }
                    // 把group为9的结点设定在第9行
                    if (d.group === 9) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第9行
                        // 计算均匀分布的x坐标
                        const group9Nodes = nodes.filter(node => node.group === 9);
                        d.fx = 0.5*this.svgWidth+(group9Nodes.indexOf(d) -group9Nodes.length/2)*spacing;
                    }
                    // 把group为10的结点设定在第10行
                    if (d.group === 10) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第10行
                        // 计算均匀分布的x坐标
                        const group10Nodes = nodes.filter(node => node.group === 10);
                        d.fx = 0.5*this.svgWidth+(group10Nodes.indexOf(d) -group10Nodes.length/2)*spacing;
                    }
                    // 把group为11的结点设定在第11行
                    if (d.group === 11) {
                        d.fy=margin*(cnt+0.5*(d.group-1));//固定y坐标在第11行
                        // 计算均匀分布的x坐标
                        const group11Nodes = nodes.filter(node => node.group === 11);
                        if(group11Nodes.indexOf(d)===1)
                            d.fx = 0.5*this.svgWidth+(group11Nodes.indexOf(d) -group11Nodes.length/2)*spacing*0.4;
                        else
                            d.fx = 0.5*this.svgWidth+(group11Nodes.indexOf(d) -group11Nodes.length/2)*spacing*1.6;
                    }
                    */
                        d.fy=margin*(cnt+0.45*(d.group-1));//固定y坐标在第d.group行
                        // 计算均匀分布的x坐标
                    const groupNodes = nodes.filter(node => node.group === d.group);
                        d.fx = 0.5 * this.svgWidth + (groupNodes.indexOf(d) - groupNodes.length / 2) * spacing *1.28; 
                });

                // console.log(nodes)

                // 定义了一个力学模拟，在每个tick步骤的时候运行ticked函数
                this.simulation = d3.forceSimulation(nodes)
                    // 这里用distance属性使连线变长
                    .force("link", d3.forceLink(links).id(d => d.id).distance(50))
                    .force("charge", d3.forceManyBody())
                    .force("collide", d3.forceCollide(this.nodeRadius))
                    // .force("center", d3.forceCenter(this.svgWidth / 2, this.svgHeight / 2))
                    // .force("boundingBox", this.boundingBoxForce())
                    .on("tick", this.ticked);

                const svg = d3.select(this.$refs.chartContainer) //选择文档中的chartContainer元素
                    .append('svg') //添加一个svg元素
                    .attr("width", this.svgWidth)
                    .attr("height", this.svgHeight)
                    .attr("viewBox", [0, 0, this.svgWidth, this.svgHeight])
                    .attr("style", "max-width: 100%; height: auto;");

                // 创建svg线段元素，并设置他们的格式
                const link = svg.append("g")//g表示group，一个容器元素，用于将很多svg元素组合到一起
                    .selectAll('g')
                    .data(links)//绑定links数组
                    .join('g');

                // 在线段组中添加线段
                link.append("line")
                    .attr("stroke", "#999")
                    .attr("stroke-opacity", 0.6)
                    .attr("stroke-width", d => Math.sqrt(d.value));


                // 在线段组中添加文本
                link.append("text")
                    .attr('class', 'text-link')
                    .attr('x', d => 0.5 * (d.x1 + d.x2))
                    .attr('y', d => 0.5 * (d.y1 + d.y2))
                    .attr("text-anchor", "middle") // 水平居中
                    .attr("dominant-baseline", "central") // 垂直居中
                    .style('fill', "black") // 设置字体颜色
                    .style('font-size', '10px') // 设置字体大小
                    .style('font-family', 'Times New Roman') // 设置字体
                    .style('font-style', 'italic')
                    .text(d => d.linkName); // 设置文本内容


                console.log(link)
                // 创建一个节点组来包含圆和文本
                const node = svg.append("g")
                    .attr("class", "nodes") // 给组添加一个类，以便我们可以引用它
                    .selectAll("g")
                    .data(nodes)
                    .join("g"); // 为每个节点数据创建一个'g'元素

                // 在节点组中添加圆形
                node.append("circle")
                    .attr("r", this.nodeRadius)
                    // .attr("fill", d => color(d.group))
                    .attr("fill", d => this.assignFillColor(d))
                    .attr("stroke", d => this.assignStrokeColor(d))
                    .attr("stroke-width", 1.5);

                // 在节点组中添加文本
                node.append("text")
                    .attr('class', 'text-inner')
                    .attr('x', d => d.x)
                    .attr('y', d => d.y)
                    .attr("text-anchor", "middle") // 水平居中
                    .attr("dominant-baseline", "central") // 垂直居中
                    .style('font-size', '12px') // 设置字体大小
                    .style('fill', d => this.assignTextColor(d))
                    .text(d => d.title); // 将节点数据的id设置为文本内容
                
                
                // 给所有节点的下方都再添加第2个文本
                node.append("text")
                    .attr("text-anchor", "middle") // 文本靠中间对齐
                    .attr('class', 'text-bottom')
                    .attr("dominant-baseline", "central") // 垂直居中
                    .style('font-size', '10px') // 设置字体大小
                    .style('fill', "black") // 设置字体颜色
                    .style('font-family', 'Times New Roman') // 设置字体
                    .style('font-weight', 'bold')
                    .text(d => d.name);


                // node.each(function (d) {
                //     // 给属于group1的节点组中根据条件添加第2个文本，位于圆形的左侧
                //     if (d.group === 1) {
                //         d3.select(this).append("text")
                //             .attr("text-anchor", "end") // 文本靠右侧对齐
                //             .attr('class', 'text-left')
                //             .attr("dominant-baseline", "central") // 垂直居中
                //             .style('font-size', '10px') // 设置字体大小
                //             .style('fill', "black") // 设置字体颜色
                //             .style('font-family', 'Times New Roman') // 设置字体
                //             .style('font-weight', 'bold')
                //             .text(d => d.name); // 设置文本内容
                //     }
                //     // 给属于group2的节点组中根据条件添加第2个文本，位于圆形的右侧
                //     if (d.group === 2) {
                //         d3.select(this).append("text")
                //             .attr("text-anchor", "start") // 文本靠右侧对齐
                //             .attr('class', 'text-right')
                //             .attr("dominant-baseline", "central") // 垂直居中
                //             .style('font-size', '10px') // 设置字体大小
                //             .style('fill', "black") // 设置字体颜色
                //             .style('font-family', 'Times New Roman') // 设置字体
                //             .style('font-weight', 'bold')
                //             .text(d => d.name); // 设置文本内容
                //     }
                //     // 给属于不属于group1/2的节点组中根据条件添加第2个文本，位于圆形的下方
                //     if (d.group !== 1 && d.group !== 2) {
                //         d3.select(this).append("text")
                //             .attr("text-anchor", "middle") // 文本靠中间对齐
                //             .attr('class', 'text-bottom')
                //             .attr("dominant-baseline", "central") // 垂直居中
                //             .style('font-size', '10px') // 设置字体大小
                //             .style('fill', "black") // 设置字体颜色
                //             .style('font-family', 'Times New Roman') // 设置字体
                //             .style('font-weight', 'bold')
                //             .text(d => d.name); // 设置文本内容
                //     }
                // });

                // console.log(node);

                // 添加拖拽行为，包含开始、进行和结束时的行为
                node.call(d3.drag()
                    .on("start", this.dragstarted)
                    .on("drag", this.dragged)
                    .on("end", this.dragended));
            }

        },
        ticked() {
            const link = this.$refs.chartContainer.querySelectorAll('line');
            const node = this.$refs.chartContainer.querySelectorAll('circle');
            const textInner = this.$refs.chartContainer.querySelectorAll('.text-inner');
            const textLeft = this.$refs.chartContainer.querySelectorAll('.text-left');
            const textRight = this.$refs.chartContainer.querySelectorAll('.text-right');
            const textBottom = this.$refs.chartContainer.querySelectorAll('.text-bottom');
            const textLink = this.$refs.chartContainer.querySelectorAll('.text-link');

            link.forEach(lk => {
                lk.setAttribute('x1', lk.__data__.source.x);
                lk.setAttribute('y1', lk.__data__.source.y);
                lk.setAttribute('x2', lk.__data__.target.x);
                lk.setAttribute('y2', lk.__data__.target.y);
            });

            node.forEach(nd => {
                nd.setAttribute('cx', nd.__data__.x);
                nd.setAttribute('cy', nd.__data__.y);
            });

            textInner.forEach(td => {
                td.setAttribute('x', td.__data__.x);
                td.setAttribute('y', td.__data__.y);
            });

            textLeft.forEach(tld => {
                tld.setAttribute('x', tld.__data__.x - this.nodeRadius - 5);
                tld.setAttribute('y', tld.__data__.y);
            });
            textRight.forEach(trd => {
                trd.setAttribute('x', trd.__data__.x + this.nodeRadius + 20);
                trd.setAttribute('y', trd.__data__.y);
            });
            textBottom.forEach(trd => {
                trd.setAttribute('x', trd.__data__.x);
                trd.setAttribute('y', trd.__data__.y + this.nodeRadius + 10);
            });
            textLink.forEach(tl => {
                tl.setAttribute('x', 0.5 * (tl.__data__.source.x + tl.__data__.target.x));
                tl.setAttribute('y', 0.5 * (tl.__data__.source.y + tl.__data__.target.y));
            });

        },

        dragstarted(event) {
            if (!event.active) this.simulation.alphaTarget(0.3).restart();
            event.subject.fx = event.subject.x;
            event.subject.fy = event.subject.y;
        },

        dragged(event, d) {
        //    /* if (d.group === 1 || d.group === 2 || d.group === 3 || d.group === 4 || d.group === 5 || d.group === 6 || d.group === 7)*/ if (d.group !== 15){
        //         event.subject.fy = event.y; // 只更新 y，保持 x 固定
        //     } else {
        //         event.subject.fx = event.x;
        //         event.subject.fy = event.y;
        //     }
        if (d.group !== 50){
                event.subject.fx = event.x; // 只更新 x，保持 y 固定
            } else {
                event.subject.fx = event.x;
                event.subject.fy = event.y;
            }


        },

        dragended(event, d) {
            if (!event.active) this.simulation.alphaTarget(0);
          /*  if (d.group !== 1 && d.group !== 2 && d.group !== 3 && d.group !== 4 && d.group !== 5 && d.group !== 6 && d.group !== 7)*/
            // if (d.group === 15) {
            //     event.subject.fx = null;
            // }
            // event.subject.fy = null;
            if (d.group === 50) {
                event.subject.fy = null;
            }
            event.subject.fx = null;
        },

        assignFillColor(d) {
  
           return d.color
            /*if (d.group !== 50 ) {
                return "#C6DCF0"
            }
            if (d.group === 50) {
                return "green"
            }
            else {
                return "white"
            }*/
        },
        assignStrokeColor(d) {
            if (d.color === "white")
                return "white"
        else
                return "black"
        },
        assignTextColor(d) {
            if (d.group === 80) {
                return "white"
            }
            else {
                return "black"
            }
        }
    },

    beforeUnmount() {
        // 停止模拟
        if (this.simulation) {
            this.simulation.stop();
        }
    }
}
</script>

<style>
/* 全局样式 */
.button-container {
    display: flex;
    justify-content: center;
    align-items: flex-start;
    position: absolute;
    /* 或者使用 fixed 根据需求 */
    top: 20;
    left: 0;
    right: 0;
}
</style>
